import{_ as s,o as e,c as t,ag as n}from"./chunks/framework.-Wrcbzkw.js";const g=JSON.parse('{"title":"进制与位运算","description":"","frontmatter":{},"headers":[],"relativePath":"basic/进制与位运算/进制与位运算.md","filePath":"basic/进制与位运算/进制与位运算.md","lastUpdated":1778838640000}'),i={name:"basic/进制与位运算/进制与位运算.md"};function l(o,a,r,p,d,c){return e(),t("div",null,[...a[0]||(a[0]=[n(`<h1 id="进制与位运算" tabindex="-1">进制与位运算 <a class="header-anchor" href="#进制与位运算" aria-label="Permalink to &quot;进制与位运算&quot;">​</a></h1><h2 id="一、进制概述" tabindex="-1">一、进制概述 <a class="header-anchor" href="#一、进制概述" aria-label="Permalink to &quot;一、进制概述&quot;">​</a></h2><h3 id="_1-1-常见进制" tabindex="-1">1.1 常见进制 <a class="header-anchor" href="#_1-1-常见进制" aria-label="Permalink to &quot;1.1 常见进制&quot;">​</a></h3><ul><li><strong>二进制（Binary）</strong>：由 0 和 1 组成，逢二进一，基数是 2</li><li><strong>八进制（Octal）</strong>：由 0-7 组成，逢八进一，基数是 8</li><li><strong>十进制（Decimal）</strong>：由 0-9 组成，逢十进一，基数是 10</li><li><strong>十六进制（Hexadecimal）</strong>：由 0-9 和 A-F 组成，逢十六进一，基数是 16</li></ul><h3 id="_1-2-进制转换" tabindex="-1">1.2 进制转换 <a class="header-anchor" href="#_1-2-进制转换" aria-label="Permalink to &quot;1.2 进制转换&quot;">​</a></h3><p><strong>十进制转其他进制</strong>：除基取余，逆序余数</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>十进制 13 转二进制：13 ÷ 2 = 6 ... 1</span></span>
<span class="line"><span>6 ÷ 2 = 3 ... 0</span></span>
<span class="line"><span>3 ÷ 2 = 1 ... 1</span></span>
<span class="line"><span>1 ÷ 2 = 0 ... 1</span></span>
<span class="line"><span>结果：1101</span></span></code></pre></div><p><strong>其他进制转十进制</strong>：按权展开求和</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>二进制 1101 转十进制：</span></span>
<span class="line"><span>1×2³ + 1×2² + 0×2¹ + 1×2⁰ = 8 + 4 + 0 + 1 = 13</span></span></code></pre></div><h2 id="二、位运算" tabindex="-1">二、位运算 <a class="header-anchor" href="#二、位运算" aria-label="Permalink to &quot;二、位运算&quot;">​</a></h2><h3 id="_2-1-按位与" tabindex="-1">2.1 按位与（&amp;） <a class="header-anchor" href="#_2-1-按位与" aria-label="Permalink to &quot;2.1 按位与（&amp;）&quot;">​</a></h3><p>对应位都为 1 时结果为 1</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5 &amp; 3 = 0101 &amp; 0011 = 0001 = 1</span></span></code></pre></div><h3 id="_2-2-按位或" tabindex="-1">2.2 按位或（|） <a class="header-anchor" href="#_2-2-按位或" aria-label="Permalink to &quot;2.2 按位或（|）&quot;">​</a></h3><p>对应位有一个为 1 时结果就为 1</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5 | 3 = 0101 | 0011 = 0111 = 7</span></span></code></pre></div><h3 id="_2-3-按位异或" tabindex="-1">2.3 按位异或（^） <a class="header-anchor" href="#_2-3-按位异或" aria-label="Permalink to &quot;2.3 按位异或（^）&quot;">​</a></h3><p>对应位相同时为 0，不同时为 1</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>5 ^ 3 = 0101 ^ 0011 = 0110 = 6</span></span></code></pre></div><p><strong>特性</strong>：<code>a ^ a = 0</code>，<code>a ^ 0 = a</code></p><h3 id="_2-4-移位运算" tabindex="-1">2.4 移位运算 <a class="header-anchor" href="#_2-4-移位运算" aria-label="Permalink to &quot;2.4 移位运算&quot;">​</a></h3><ul><li><strong>左移（&lt;&lt;）</strong>：<code>n &lt;&lt; m = n × 2^m</code></li><li><strong>右移（&gt;&gt;）</strong>：<code>n &gt;&gt; m = n ÷ 2^m</code></li></ul><h2 id="三、原码、反码、补码" tabindex="-1">三、原码、反码、补码 <a class="header-anchor" href="#三、原码、反码、补码" aria-label="Permalink to &quot;三、原码、反码、补码&quot;">​</a></h2><ul><li><strong>原码</strong>：符号位 + 绝对值的二进制</li><li><strong>反码</strong>：正数不变，负数其余位取反</li><li><strong>补码</strong>：正数不变，负数为反码 + 1</li></ul><p>补码让计算机可以用加法实现减法。</p><h2 id="四、位、字节与编码" tabindex="-1">四、位、字节与编码 <a class="header-anchor" href="#四、位、字节与编码" aria-label="Permalink to &quot;四、位、字节与编码&quot;">​</a></h2><ul><li><strong>位（bit）</strong>：最小单位，0 或 1</li><li><strong>字节（Byte）</strong>：8 位</li></ul><p><strong>编码</strong>：</p><ul><li>ASCII：7 位，128 个字符</li><li>Unicode：统一码</li><li>UTF-8：可变长度，中文 3 字节</li></ul>`,29)])])}const u=s(i,[["render",l]]);export{g as __pageData,u as default};
